import React, { useState, useEffect, useRef } from 'react';
import { 
  Zap, Radio, BarChart3, Users, Filter, Plus, 
  ArrowUpRight, Bookmark, MoreHorizontal, Search, 
  Bell, Briefcase, Settings, LogOut, 
  Hash, TrendingUp, Globe, Clock,
  MessageCircle, Share2, Shield,
  Send, Mic, Phone, Video, Lock, FileText,
  User, CheckCircle2, Newspaper, Menu, X
} from 'lucide-react';

// --- TYPES ---

interface BrandTheme {
  bg: string;
  sidebar: string;
  text: string;
  accent: string;
  highlight: string;
}

interface Brand {
  name: string;
  theme: BrandTheme;
}

interface Engagement {
  upvotes: number;
  comments: number;
}

interface Signal {
  id: number;
  author: string;
  handle: string;
  avatar: string;
  type: string;
  metric: string;
  value: string;
  content: string;
  tags: string[];
  engagement: Engagement;
  time: string;
  color: string;
}

interface IntelItem {
  id: number;
  topic: string;
  title: string;
  source: string;
  time: string;
}

interface SquadMember {
  name: string;
  role: string;
  match: string;
  skill: string;
}

interface ChatThread {
  id: number;
  user: string;
  role: string;
  avatar: string;
  lastMsg: string;
  time: string;
  unread: number;
  status: 'online' | 'offline' | 'away';
  tags?: string[];
}

interface Message {
  id: number;
  sender: 'me' | 'them';
  text: string;
  time: string;
}

// --- 1. NEW BRAND IDENTITY & DATA ---

const BRAND: Brand = {
  name: "CoFound",
  theme: {
    bg: "bg-[#F4F4F5]", // Zinc-100: Paper-like background
    sidebar: "bg-white",
    text: "text-zinc-900",
    accent: "bg-zinc-900 text-white", // Monochrome primary
    highlight: "text-indigo-600"
  }
};

const SIGNALS: Signal[] = [
  {
    id: 1,
    author: "Sanjay Aaron",
    handle: "@sanjay_builds",
    avatar: "SA",
    type: "MILESTONE",
    metric: "ARR",
    value: "$10k",
    content: "Crossed the $10k MRR mark today. The pivot to B2B finally paid off. Here are the 3 cold email templates that worked.",
    tags: ["SaaS", "Growth", "B2B"],
    engagement: { upvotes: 342, comments: 45 },
    time: "2h ago",
    color: "bg-emerald-50 text-emerald-700 border-emerald-200"
  },
  {
    id: 2,
    author: "Priya Sharma",
    handle: "@priya_tech",
    avatar: "PS",
    type: "ASK",
    metric: "HELP",
    value: "URGENT",
    content: "We're facing a high churn rate (8%) after the latest UI update. Looking for UX researchers who specialize in fintech onboarding flows.",
    tags: ["Product", "UX", "Hiring"],
    engagement: { upvotes: 89, comments: 120 },
    time: "5h ago",
    color: "bg-amber-50 text-amber-700 border-amber-200"
  },
  {
    id: 3,
    author: "Rahul Verma",
    handle: "@rahul_design",
    avatar: "RV",
    type: "LAUNCH",
    metric: "BETA",
    value: "LIVE",
    content: "DesignSystem.io is live on Product Hunt! It's a Figma plugin to automate your handoff process. Would love your support.",
    tags: ["Launch", "Tooling"],
    engagement: { upvotes: 56, comments: 12 },
    time: "1d ago",
    color: "bg-violet-50 text-violet-700 border-violet-200"
  },
  {
    id: 4,
    author: "David Chen",
    handle: "@dchen_vc",
    avatar: "DC",
    type: "INTEL",
    metric: "MARKET",
    value: "TREND",
    content: "Noticing a massive shift in investor sentiment towards 'Vertical AI' agents over generic LLM wrappers. The moat is in the proprietary data.",
    tags: ["VC", "AI", "Trends"],
    engagement: { upvotes: 890, comments: 44 },
    time: "3h ago",
    color: "bg-blue-50 text-blue-700 border-blue-200"
  }
];

const INTEL_BRIEFING: IntelItem[] = [
  { id: 1, topic: "Regulations", title: "New DPDPA Act Compliance Guide", source: "LegalTech", time: "10m ago" },
  { id: 2, topic: "Market", title: "SaaS Multiples compress to 5.4x", source: "TechCrunch", time: "1h ago" },
  { id: 3, topic: "Funding", title: "YCombinator increases deal size", source: "YC Blog", time: "3h ago" },
];

const SQUAD_SUGGESTIONS: SquadMember[] = [
  { name: "Arun Kumar", role: "CTO @ FinBase", match: "98%", skill: "Rust / Systems" },
  { name: "Sarah Lee", role: "Angel Investor", match: "85%", skill: "Fintech" },
  { name: "Meera Reddy", role: "Growth Lead", match: "92%", skill: "B2B Sales" },
];

const CHAT_THREADS: ChatThread[] = [
  { 
    id: 1, 
    user: "Arun Kumar", 
    role: "CTO @ FinBase",
    avatar: "AK", 
    lastMsg: "I've reviewed the API docs. The webhook implementation looks solid, but we need to discuss rate limits.",
    time: "10:42 AM", 
    unread: 2,
    status: "online",
    tags: ["Tech", "Urgent"]
  },
  { 
    id: 2, 
    user: "Sarah Lee", 
    role: "Angel Investor",
    avatar: "SL", 
    lastMsg: "Let's schedule a call for Tuesday. I'm interested in the B2B pivot strategy.",
    time: "Yesterday", 
    unread: 0,
    status: "offline",
    tags: ["Deal Flow"]
  },
  { 
    id: 3, 
    user: "Meera Reddy", 
    role: "Growth Lead",
    avatar: "MR", 
    lastMsg: "Sent you the draft for the press release.",
    time: "Mon", 
    unread: 0,
    status: "away",
    tags: ["Marketing"]
  },
];

const MOCK_MESSAGES: Message[] = [
  { id: 1, sender: "them", text: "Hey Sanjay, got a minute to check the new architecture?", time: "10:30 AM" },
  { id: 2, sender: "me", text: "Sure Arun, what specifically?", time: "10:32 AM" },
  { id: 3, sender: "them", text: "I've reviewed the API docs. The webhook implementation looks solid, but we need to discuss rate limits.", time: "10:42 AM" },
];

// --- 2. ATOMIC COMPONENTS (New Design System) ---

interface CardProps {
  children: React.ReactNode;
  className?: string;
  noPadding?: boolean;
}

const Card: React.FC<CardProps> = ({ children, className = "", noPadding = false }) => (
  <div className={`bg-white border border-zinc-200 shadow-[0_2px_8px_-2px_rgba(0,0,0,0.05)] rounded-xl overflow-hidden ${noPadding ? '' : 'p-5'} ${className}`}>
    {children}
  </div>
);

interface ChipProps {
  label: string;
  color?: string;
}

const Chip: React.FC<ChipProps> = ({ label, color = "bg-zinc-100 text-zinc-600" }) => (
  <span className={`px-2 py-1 rounded-md text-[10px] font-bold uppercase tracking-wider ${color}`}>
    {label}
  </span>
);

interface AvatarProps {
  initials: string;
  size?: 'sm'|'md'|'lg'|'xl';
  color?: string;
}

const Avatar: React.FC<AvatarProps> = ({ initials, size = "md", color = "bg-zinc-900" }) => {
  const sizes = { sm: "w-8 h-8 text-xs", md: "w-10 h-10 text-sm", lg: "w-16 h-16 text-xl", xl: "w-24 h-24 text-3xl" };
  return (
    <div className={`${sizes[size]} ${color} text-white rounded-lg flex items-center justify-center font-bold font-mono shadow-sm`}>
      {initials}
    </div>
  );
};

// --- 3. THE FOUNDER'S COCKPIT (New Dashboard Layout) ---

interface NavIconProps {
  icon: React.ElementType;
  active?: boolean;
  onClick?: () => void;
  label: string;
}

const NavIcon: React.FC<NavIconProps> = ({ icon: Icon, active, onClick, label }) => (
  <div onClick={onClick} className="group relative w-full flex justify-center cursor-pointer">
    <div className={`p-3 rounded-xl transition-all duration-300 ${active ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/50' : 'text-zinc-500 hover:bg-zinc-800 hover:text-white'}`}>
      <Icon size={22} strokeWidth={active ? 2.5 : 2} />
    </div>
    {/* Tooltip */}
    <span className="absolute left-16 top-1/2 -translate-y-1/2 bg-zinc-900 text-white text-xs px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap z-50">
      {label}
    </span>
    {active && <div className="absolute left-0 top-1/2 -translate-y-1/2 w-1 h-8 bg-indigo-500 rounded-r-full"></div>}
  </div>
);

// --- 4. MODULE LAYOUTS ---

// D. CHAT (New Module)
const ChatLayout: React.FC = () => {
  const [selectedThread, setSelectedThread] = useState<ChatThread>(CHAT_THREADS[0]);
  const [messages, setMessages] = useState<Message[]>(MOCK_MESSAGES);
  const [inputText, setInputText] = useState("");
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const sendMessage = () => {
    if (!inputText.trim()) return;
    setMessages([...messages, { 
      id: messages.length + 1, 
      sender: "me", 
      text: inputText, 
      time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) 
    }]);
    setInputText("");
  };

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  return (
    <div className="h-full flex gap-6">

      {/* 1. The Wire (Inbox List) */}
      <Card className="w-80 flex flex-col !p-0 border-r border-zinc-200">
        <div className="p-4 border-b border-zinc-100 flex justify-between items-center bg-zinc-50/50">
          <h2 className="font-bold text-lg">Comms</h2>
          <button className="p-2 hover:bg-zinc-200 rounded-lg"><Plus size={18} /></button>
        </div>
        <div className="p-2">
           <div className="relative mb-2">
              <Search className="absolute left-3 top-2.5 text-zinc-400" size={14} />
              <input type="text" placeholder="Filter threads..." className="w-full bg-zinc-100 pl-9 pr-3 py-2 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500" />
           </div>
        </div>
        <div className="flex-1 overflow-y-auto">
           {CHAT_THREADS.map(thread => (
             <div 
                key={thread.id} 
                onClick={() => setSelectedThread(thread)}
                className={`p-4 border-b border-zinc-50 cursor-pointer transition-colors hover:bg-zinc-50 relative ${selectedThread.id === thread.id ? 'bg-indigo-50/50' : ''}`}
             >
                {selectedThread.id === thread.id && <div className="absolute left-0 top-0 bottom-0 w-1 bg-indigo-600"></div>}
                <div className="flex gap-3">
                   <div className="relative">
                      <Avatar initials={thread.avatar} size="md" color={selectedThread.id === thread.id ? 'bg-indigo-600' : 'bg-zinc-900'} />
                      <div className={`absolute -bottom-1 -right-1 w-3 h-3 border-2 border-white rounded-full ${thread.status === 'online' ? 'bg-emerald-500' : 'bg-zinc-300'}`}></div>
                   </div>
                   <div className="flex-1 min-w-0">
                      <div className="flex justify-between items-baseline mb-1">
                         <h4 className={`text-sm font-bold truncate ${selectedThread.id === thread.id ? 'text-indigo-900' : 'text-zinc-900'}`}>{thread.user}</h4>
                         <span className="text-[10px] text-zinc-400 font-mono">{thread.time}</span>
                      </div>
                      <p className={`text-xs truncate ${thread.unread > 0 ? 'font-bold text-zinc-900' : 'text-zinc-500'}`}>
                        {thread.lastMsg}
                      </p>
                      {thread.tags && (
                        <div className="flex gap-1 mt-2">
                           {thread.tags.map(tag => (
                             <span key={tag} className="px-1.5 py-0.5 bg-zinc-100 text-[9px] font-bold text-zinc-500 uppercase rounded">{tag}</span>
                           ))}
                        </div>
                      )}
                   </div>
                </div>
             </div>
           ))}
        </div>
      </Card>

      {/* 2. The Stream (Active Chat) */}
      <Card className="flex-1 flex flex-col !p-0">

        {/* Chat Header */}
        <div className="h-16 border-b border-zinc-100 flex items-center justify-between px-6 bg-white shrink-0">
           <div className="flex items-center gap-3">
              <Avatar initials={selectedThread.avatar} size="sm" />
              <div>
                 <h3 className="font-bold text-sm text-zinc-900">{selectedThread.user}</h3>
                 <p className="text-xs text-emerald-600 flex items-center gap-1 font-medium">
                    <Zap size={10} className="fill-emerald-600" /> Active Now
                 </p>
              </div>
           </div>
           <div className="flex items-center gap-2 text-zinc-400">
              <button className="p-2 hover:bg-zinc-50 rounded-lg hover:text-indigo-600"><Phone size={18} /></button>
              <button className="p-2 hover:bg-zinc-50 rounded-lg hover:text-indigo-600"><Video size={18} /></button>
              <button className="p-2 hover:bg-zinc-50 rounded-lg hover:text-indigo-600"><MoreHorizontal size={18} /></button>
           </div>
        </div>

        {/* Messages Area */}
        <div className="flex-1 bg-zinc-50/50 p-6 overflow-y-auto space-y-6">
           <div className="flex justify-center">
              <span className="text-[10px] font-bold text-zinc-400 bg-zinc-100 px-3 py-1 rounded-full uppercase tracking-widest">Today</span>
           </div>

           {/* Encrypted Notice */}
           <div className="flex justify-center mb-6">
              <div className="flex items-center gap-2 text-xs text-zinc-400 bg-amber-50 px-3 py-1.5 rounded border border-amber-100">
                 <Lock size={12} /> Messages are end-to-end encrypted.
              </div>
           </div>

           {messages.map(msg => (
             <div key={msg.id} className={`flex ${msg.sender === 'me' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[70%] ${msg.sender === 'me' ? 'items-end' : 'items-start'} flex flex-col`}>
                   <div className={`p-4 rounded-2xl text-sm leading-relaxed shadow-sm relative group ${
                      msg.sender === 'me' 
                        ? 'bg-zinc-900 text-white rounded-tr-none' 
                        : 'bg-white border border-zinc-200 text-zinc-800 rounded-tl-none'
                   }`}>
                      {msg.text}
                      <span className={`text-[10px] absolute bottom-1 ${msg.sender === 'me' ? 'left-2 text-zinc-500' : 'right-2 text-zinc-300'} opacity-0 group-hover:opacity-100 transition-opacity`}>
                        {msg.time}
                      </span>
                   </div>
                   <span className="text-[10px] text-zinc-400 mt-1 font-mono px-1">{msg.time}</span>
                </div>
             </div>
           ))}
           <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <div className="p-4 bg-white border-t border-zinc-200 shrink-0">
           <div className="bg-zinc-50 border border-zinc-200 rounded-xl p-2 flex items-end gap-2 focus-within:ring-2 focus-within:ring-indigo-500/20 focus-within:border-indigo-500 transition-all">
              <button className="p-2 text-zinc-400 hover:text-indigo-600 transition-colors"><Plus size={20} /></button>
              <textarea 
                value={inputText}
                onChange={(e) => setInputText(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && !e.shiftKey && (e.preventDefault(), sendMessage())}
                placeholder="Type a secure message..." 
                className="flex-1 bg-transparent border-none outline-none text-sm text-zinc-900 placeholder:text-zinc-400 resize-none py-2 max-h-32"
                rows={1}
              />
              <button className="p-2 text-zinc-400 hover:text-indigo-600 transition-colors"><Mic size={20} /></button>
              <button 
                onClick={sendMessage}
                className={`p-2 rounded-lg transition-all ${inputText.trim() ? 'bg-indigo-600 text-white shadow-md' : 'bg-zinc-200 text-zinc-400'}`}
              >
                <Send size={18} />
              </button>
           </div>
        </div>
      </Card>

      {/* 3. The Dossier (Context Sidebar) */}
      <div className="w-80 flex flex-col gap-4">
         <Card className="flex flex-col items-center text-center pt-8">
            <Avatar initials={selectedThread.avatar} size="xl" />
            <h2 className="font-bold text-lg mt-4">{selectedThread.user}</h2>
            <p className="text-zinc-500 text-sm mb-4">{selectedThread.role}</p>

            <div className="w-full grid grid-cols-2 gap-2 mb-6">
               <button className="flex flex-col items-center justify-center p-2 rounded-lg hover:bg-zinc-50 border border-transparent hover:border-zinc-200 transition-all">
                  <div className="w-8 h-8 rounded-full bg-emerald-50 text-emerald-600 flex items-center justify-center mb-1"><Globe size={16} /></div>
                  <span className="text-xs font-bold text-zinc-600">Website</span>
               </button>
               <button className="flex flex-col items-center justify-center p-2 rounded-lg hover:bg-zinc-50 border border-transparent hover:border-zinc-200 transition-all">
                  <div className="w-8 h-8 rounded-full bg-indigo-50 text-indigo-600 flex items-center justify-center mb-1"><FileText size={16} /></div>
                  <span className="text-xs font-bold text-zinc-600">Deck</span>
               </button>
            </div>

            <div className="w-full text-left">
               <h4 className="text-xs font-bold text-zinc-400 uppercase tracking-widest mb-3">Private Notes</h4>
               <div className="bg-yellow-50/50 border border-yellow-100 rounded-lg p-3 text-sm text-zinc-700 leading-relaxed font-mono">
                  "Met at SaaSBOOMi. Interested in our API pricing. Key decision maker."
               </div>
            </div>
         </Card>

         <Card className="flex-1">
             <h4 className="text-xs font-bold text-zinc-400 uppercase tracking-widest mb-3">Shared Files</h4>
             <div className="space-y-3">
                {[1,2].map(i => (
                  <div key={i} className="flex items-center gap-3 p-2 hover:bg-zinc-50 rounded-lg cursor-pointer transition-colors">
                     <div className="w-8 h-8 bg-zinc-100 rounded flex items-center justify-center text-zinc-500"><FileText size={16} /></div>
                     <div className="flex-1 min-w-0">
                        <p className="text-sm font-bold text-zinc-800 truncate">NDA_Agreement_v{i}.pdf</p>
                        <p className="text-[10px] text-zinc-400">2.4 MB • 12 Oct</p>
                     </div>
                  </div>
                ))}
             </div>
         </Card>
      </div>

    </div>
  );
};

// A. PULSE (The Feed Reimagined)
const PulseLayout: React.FC = () => (
  <div className="grid grid-cols-12 gap-6 h-[calc(100vh-140px)]">

    {/* Left: The Stream (Masonry/Timeline feel) */}
    <div className="col-span-8 overflow-y-auto pr-2 space-y-6 pb-20 no-scrollbar">

      {/* Composer Micro-Interaction */}
      <Card className="flex gap-4 items-center !p-4 border-l-4 border-indigo-500">
        <Avatar initials="SA" size="md" />
        <input type="text" placeholder="Share a milestone, ask for help, or broadcast a launch..." className="flex-1 bg-transparent outline-none text-zinc-600 font-medium placeholder:text-zinc-400" />
        <div className="flex gap-2 text-zinc-400">
           <button className="p-2 hover:bg-zinc-50 rounded-lg transition-colors"><Radio size={18} /></button>
           <button className="p-2 hover:bg-zinc-50 rounded-lg transition-colors"><Hash size={18} /></button>
        </div>
      </Card>

      <div className="flex items-center justify-between">
         <h3 className="text-xs font-bold text-zinc-400 uppercase tracking-widest">Live Signals</h3>
         <div className="flex gap-2">
            <button className="text-xs font-bold px-3 py-1 bg-white border border-zinc-200 rounded-full text-zinc-600 hover:bg-zinc-50">Top</button>
            <button className="text-xs font-bold px-3 py-1 bg-transparent text-zinc-400 hover:text-zinc-600">Latest</button>
         </div>
      </div>

      {SIGNALS.map((signal) => (
        <div key={signal.id} className="group relative pl-8 border-l-2 border-zinc-200 hover:border-indigo-200 transition-colors">
          <div className="absolute -left-[9px] top-6 w-4 h-4 bg-white border-2 border-zinc-300 rounded-full group-hover:border-indigo-500 transition-colors"></div>

          <Card className="hover:shadow-md transition-shadow duration-300">
            {/* Header */}
            <div className="flex justify-between items-start mb-3">
               <div className="flex items-center gap-3">
                 <Avatar initials={signal.avatar} size="md" />
                 <div>
                   <div className="flex items-center gap-2">
                     <span className="font-bold text-zinc-900">{signal.author}</span>
                     <span className="text-xs text-zinc-400">{signal.handle}</span>
                   </div>
                   <div className="flex items-center gap-2 mt-0.5">
                      <Chip label={signal.type} color={signal.color} />
                      <span className="text-xs text-zinc-400">• {signal.time}</span>
                   </div>
                 </div>
               </div>
               <button className="text-zinc-300 hover:text-zinc-600"><MoreHorizontal size={18} /></button>
            </div>

            {/* Content */}
            <div className="mb-4">
              <p className="text-zinc-700 leading-relaxed text-sm md:text-base">{signal.content}</p>
            </div>

            {/* Metric/Signal Box */}
            <div className="bg-zinc-50 rounded-lg p-3 border border-zinc-100 flex items-center justify-between mb-4">
               <div className="flex gap-4">
                  <div>
                    <div className="text-[10px] uppercase text-zinc-400 font-bold tracking-wider">{signal.metric}</div>
                    <div className="font-mono font-bold text-zinc-900">{signal.value}</div>
                  </div>
                  {signal.tags.map(tag => (
                    <div key={tag} className="hidden sm:block">
                      <div className="text-[10px] uppercase text-zinc-400 font-bold tracking-wider">TAG</div>
                      <div className="font-medium text-zinc-600 text-sm">#{tag}</div>
                    </div>
                  ))}
               </div>
               <div className="h-8 w-20 bg-white rounded border border-zinc-200 flex items-center justify-center">
                  <TrendingUp size={16} className="text-emerald-500" />
               </div>
            </div>

            {/* Actions */}
            <div className="flex items-center gap-6 pt-2 border-t border-zinc-100/50">
               <button className="flex items-center gap-2 text-zinc-500 hover:text-indigo-600 text-sm font-medium transition-colors">
                  <ArrowUpRight size={18} /> <span className="font-mono">{signal.engagement.upvotes}</span>
               </button>
               <button className="flex items-center gap-2 text-zinc-500 hover:text-indigo-600 text-sm font-medium transition-colors">
                  <MessageCircle size={18} /> <span className="font-mono">{signal.engagement.comments}</span>
               </button>
               <button className="flex items-center gap-2 text-zinc-500 hover:text-indigo-600 text-sm font-medium transition-colors ml-auto">
                  <Share2 size={18} />
               </button>
            </div>
          </Card>
        </div>
      ))}
    </div>

    {/* Right: The Radar (Quick info) */}
    <div className="col-span-4 space-y-6">

      <Card className="bg-gradient-to-br from-indigo-900 to-zinc-900 text-white !border-none">
         <div className="flex items-center justify-between mb-6">
            <h3 className="font-bold flex items-center gap-2"><Shield size={16} className="text-indigo-400"/> Verification</h3>
            <span className="text-xs bg-white/10 px-2 py-0.5 rounded text-indigo-200">Pro</span>
         </div>
         <p className="text-sm text-zinc-300 mb-4 leading-relaxed">
           Your startup profile is <b className="text-white">65% complete</b>. Verify your incorporation to unlock the investor database.
         </p>
         <button className="w-full py-2 bg-white text-zinc-900 font-bold text-sm rounded-lg hover:bg-zinc-100 transition-colors">Complete Verification</button>
      </Card>

      <div className="bg-white rounded-xl border border-zinc-200 p-0 overflow-hidden">
         <div className="p-4 border-b border-zinc-100 flex justify-between items-center">
